59: \treturn hasUID || hasType\n60: }\n61: \n62: // MigrateDatasourceNameToRef converts a datasource name/uid string to a reference object\n63: // Matches the frontend migrateDatasourceNameToRef function in DashboardMigrator.ts\n64: // Options:\n65: //   - returnDefaultAsNull: if true, returns nil for \"default\" datasources (used in V33)\n66: //   - returnDefaultAsNull: if false, returns reference for \"default\" datasources (used in V36)\n67: func MigrateDatasourceNameToRef(nameOrRef interface{}, options map[string]bool, datasources []DataSourceInfo) map[string]interface{} {\n68: \tif options[\"returnDefaultAsNull\"] \u0026\u0026 (nameOrRef == nil || nameOrRef == \"default\") {\n69: \t\treturn nil\n70: \t}\n71: \n72: \t// Frontend: if (isDataSourceRef(nameOrRef)) { return nameOrRef; }\n73: \tif isDataSourceRef(nameOrRef) {\n74: \t\treturn nameOrRef.(map[string]interface{})\n75: \t}\n76: \n77: \t// Look up datasource by name/UID\n78: \tif nameOrRef == nil || nameOrRef == \"default\" {\n79: \t\tds := GetDefaultDSInstanceSettings(datasources)\n80: \t\tif ds != nil {\n81: \t\t\treturn GetDataSourceRef(ds)\n82: \t\t}\n83: \t}\n84: \n85: \t// Check if it's a string name/UID\n86: \tif str, ok := nameOrRef.(string); ok {\n87: \t\t// Handle empty string case\n88: \t\tif str == \"\" {\n89: \t\t\t// Empty string should return {} (frontend behavior)\n90: \t\t\treturn map[string]interface{}{}\n91: \t\t}\n92: \n93: \t\t// Search for matching datasource\n94: \t\tfor _, ds := range datasources {\n95: \t\t\tif str == ds.Name || str == ds.UID {\n96: \t\t\t\treturn GetDataSourceRef(\u0026DataSourceInfo{\n97: \t\t\t\t\tUID:        ds.UID,\n98: \t\t\t\t\tType:       ds.Type,\n99: \t\t\t\t\tName:       ds.Name,\n100: \t\t\t\t\tAPIVersion: ds.APIVersion,\n101: \t\t\t\t})\n102: \t\t\t}\n103: \t\t}\n104: \n105: \t\t// Unknown datasource name should be preserved as UID-only reference\n106: \t\treturn map[string]interface{}{\n107: \t\t\t\"uid\": str,\n108: \t\t}\n109: \t}\n110: \n111: \tret